#[allow(clippy::too_many_arguments)]
fn select_block_sync_roster(
    block: &SignedBlock,
    block_hash: HashOf<BlockHeader>,
    block_height: u64,
    persisted: Option<BlockSyncRosterSelection>,
    cert_hint: Option<&Qc>,
    checkpoint_hint: Option<&ValidatorSetCheckpoint>,
    state: &State,
    trusted: &iroha_config::parameters::actual::TrustedPeers,
    local_peer: &PeerId,
    mode_tag: &'static str,
    allow_uncertified: bool,
) -> Option<BlockSyncRosterSelection> {
    super::select_block_sync_roster(
        block,
        block_hash,
        block_height,
        persisted,
        cert_hint,
        checkpoint_hint,
        None,
        state,
        trusted,
        local_peer,
        ConsensusMode::Permissioned,
        mode_tag,
        allow_uncertified,
    )
}

fn sample_chunk_with_len(idx: u32, len: usize) -> crate::sumeragi::consensus::RbcChunk {
    let idx_byte = u8::try_from(idx).expect("idx fits in u8 for test chunk");
    crate::sumeragi::consensus::RbcChunk {
        block_hash: HashOf::from_untyped_unchecked(Hash::prehashed([idx_byte; Hash::LENGTH])),
        height: 1,
        view: 1,
        idx,
        epoch: 0,
        bytes: vec![0u8; len],
    }
}

fn roster_hash(roster: &[PeerId]) -> Hash {
    Hash::new(&roster.to_vec().encode())
}

fn zero_state_root() -> Hash {
    Hash::prehashed([0u8; 32])
}

fn pending_session_key(height: u64) -> SessionKey {
    let height_byte = u8::try_from(height).expect("height fits in u8 for test session key");
    (
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([height_byte; Hash::LENGTH])),
        height,
        0,
    )
}

fn commit_qc_with_signers(
    chain_id: &ChainId,
    mode_tag: &str,
    header: &BlockHeader,
    parent_state_root: Hash,
    post_state_root: Hash,
    signers: &[&KeyPair],
    signers_bitmap: Vec<u8>,
) -> Qc {
    let validator_set: Vec<_> = signers
        .iter()
        .map(|keypair| PeerId::new(keypair.public_key().clone()))
        .collect();
    let mut qc = Qc {
        phase: Phase::Commit,
        subject_block_hash: header.hash(),
        parent_state_root,
        post_state_root,
        height: header.height().get(),
        view: 0,
        epoch: 0,
        mode_tag: mode_tag.to_string(),
        highest_qc: None,
        validator_set_hash: HashOf::new(&validator_set),
        validator_set_hash_version: VALIDATOR_SET_HASH_VERSION_V1,
        validator_set,
        aggregate: QcAggregate {
            signers_bitmap: Vec::new(),
            bls_aggregate_signature: Vec::new(),
        },
    };
    let preimage = super::qc_bls_preimage(&qc, chain_id, mode_tag);
    let signatures: Vec<Vec<u8>> = signers
        .iter()
        .map(|keypair| {
            Signature::new(keypair.private_key(), &preimage)
                .payload()
                .to_vec()
        })
        .collect();
    let sig_refs: Vec<&[u8]> = signatures.iter().map(Vec::as_slice).collect();
    let aggregate_signature = iroha_crypto::bls_normal_aggregate_signatures(&sig_refs)
        .expect("aggregate commit QC signatures");
    qc.aggregate = QcAggregate {
        signers_bitmap,
        bls_aggregate_signature: aggregate_signature,
    };
    qc
}

fn sample_lane_relay_envelope(
    height: u64,
    lane_id: LaneId,
    chain_id: &ChainId,
    mode_tag: &str,
    signers: &[&KeyPair],
    signers_bitmap: u8,
) -> LaneRelayEnvelope {
    sample_lane_relay_envelope_with_bitmap(
        height,
        lane_id,
        chain_id,
        mode_tag,
        signers,
        signers_bitmap,
    )
}

fn sample_lane_relay_envelope_with_bitmap(
    height: u64,
    lane_id: LaneId,
    chain_id: &ChainId,
    mode_tag: &str,
    signers: &[&KeyPair],
    signers_bitmap: u8,
) -> LaneRelayEnvelope {
    let header = BlockHeader::new(
        NonZeroU64::new(height).expect("non-zero height"),
        None,
        None,
        None,
        1_700_000_000_000,
        0,
    );
    let qc = commit_qc_with_signers(
        chain_id,
        mode_tag,
        &header,
        Hash::new([0xBC; 4]),
        Hash::new([0xAB; 4]),
        signers,
        vec![signers_bitmap],
    );
    let settlement = LaneBlockCommitment {
        block_height: height,
        lane_id,
        dataspace_id: DataSpaceId::GLOBAL,
        tx_count: 1,
        total_local_micro: 1,
        total_xor_due_micro: 1,
        total_xor_after_haircut_micro: 1,
        total_xor_variance_micro: 0,
        swap_metadata: None,
        receipts: vec![LaneSettlementReceipt {
            source_id: [0xAA; 32],
            local_amount_micro: 1,
            xor_due_micro: 1,
            xor_after_haircut_micro: 1,
            xor_variance_micro: 0,
            timestamp_ms: 1_700_000_000_000,
        }],
    };
    LaneRelayEnvelope::new(header, Some(qc), None, settlement, 0).expect("valid envelope")
}

fn account_id_for_keypair(domain: &str, keypair: &KeyPair) -> AccountId {
    let domain_id: DomainId = domain.parse().expect("domain id");
    AccountId::new(domain_id, keypair.public_key().clone())
}

fn install_lane_manifest_registry(state: &State, lanes: &[(LaneId, DataSpaceId, Vec<AccountId>)]) {
    let mut statuses = BTreeMap::new();
    for (lane_id, dataspace_id, validators) in lanes {
        let rules = GovernanceRules {
            validators: validators.clone(),
            ..GovernanceRules::default()
        };
        let status = LaneManifestStatus {
            lane: *lane_id,
            alias: format!("lane-{}", lane_id.as_u32()),
            dataspace: *dataspace_id,
            visibility: LaneVisibility::Public,
            storage: LaneStorageProfile::FullReplica,
            governance: Some("parliament".to_string()),
            manifest_path: Some(PathBuf::from("/tmp/manifest.json")),
            governance_rules: Some(rules),
            privacy_commitments: Vec::new(),
        };
        statuses.insert(*lane_id, status);
    }
    let registry = Arc::new(LaneManifestRegistry::from_statuses(statuses));
    state.install_lane_manifests(&registry);
}

fn seed_npos_epochs(
    actor: &mut Actor,
    epoch_len: u64,
    seed_epoch0: [u8; 32],
    seed_epoch1: [u8; 32],
) {
    let roster_len = actor.effective_commit_topology().len();
    let record0 = iroha_data_model::consensus::VrfEpochRecord {
        epoch: 0,
        seed: seed_epoch0,
        epoch_length: epoch_len,
        commit_deadline_offset: 0,
        reveal_deadline_offset: 0,
        roster_len: u32::try_from(roster_len).unwrap_or(0),
        finalized: true,
        updated_at_height: epoch_len,
        participants: Vec::new(),
        late_reveals: Vec::new(),
        committed_no_reveal: Vec::new(),
        no_participation: Vec::new(),
        penalties_applied: false,
        penalties_applied_at_height: None,
        validator_election: None,
    };
    let record1 = iroha_data_model::consensus::VrfEpochRecord {
        epoch: 1,
        seed: seed_epoch1,
        epoch_length: epoch_len,
        commit_deadline_offset: 0,
        reveal_deadline_offset: 0,
        roster_len: u32::try_from(roster_len).unwrap_or(0),
        finalized: true,
        updated_at_height: epoch_len.saturating_mul(2),
        participants: Vec::new(),
        late_reveals: Vec::new(),
        committed_no_reveal: Vec::new(),
        no_participation: Vec::new(),
        penalties_applied: false,
        penalties_applied_at_height: None,
        validator_election: None,
    };

    let state = Arc::get_mut(&mut actor.state).expect("state uniquely held");
    let mut block = state.world.block();
    let params = block.parameters.get_mut();
    let npos_params = iroha_data_model::parameter::system::SumeragiNposParameters {
        epoch_length_blocks: epoch_len,
        epoch_seed: seed_epoch0,
        evidence_horizon_blocks: 0,
        ..iroha_data_model::parameter::system::SumeragiNposParameters::default()
    };
    params.custom.insert(
        iroha_data_model::parameter::system::SumeragiNposParameters::parameter_id(),
        npos_params.into_custom_parameter(),
    );
    block.vrf_epochs.insert(0, record0);
    block.vrf_epochs.insert(1, record1.clone());
    block.commit();

    if let Some(manager) = actor.epoch_manager.as_mut() {
        manager.set_params(epoch_len, 0, 0);
        manager.restore_from_record(&record1);
    }
}

fn sign_vote_for_view(
    vote: &mut crate::sumeragi::consensus::Vote,
    chain: &ChainId,
    topology: &super::network_topology::Topology,
    keypairs: &[KeyPair],
) {
    let rotated = super::topology_for_view(
        topology,
        vote.height,
        vote.view,
        super::PERMISSIONED_TAG,
        None,
    );
    let signer_idx = usize::try_from(vote.signer).expect("signer fits usize");
    let peer = rotated
        .as_ref()
        .get(signer_idx)
        .expect("signer present in rotated topology");
    let kp = keypairs
        .iter()
        .find(|kp| kp.public_key() == peer.public_key())
        .expect("matching keypair for signer");
    let preimage = super::vote_preimage(chain, super::PERMISSIONED_TAG, vote);
    let sig = Signature::new(kp.private_key(), &preimage);
    vote.bls_sig = sig.payload().to_vec();
}

fn sign_vote_for_canonical_signer(
    vote: &mut crate::sumeragi::consensus::Vote,
    chain: &ChainId,
    topology: &super::network_topology::Topology,
    keypairs: &[KeyPair],
) {
    let signature_topology = super::topology_for_view(
        topology,
        vote.height,
        vote.view,
        super::PERMISSIONED_TAG,
        None,
    );
    let canonical = ValidatorIndex::try_from(vote.signer).expect("signer fits u32");
    let view_idx = super::view_index_for_canonical_signer(canonical, &signature_topology, topology)
        .expect("canonical signer maps to view index");
    vote.signer = u32::try_from(view_idx).expect("view index fits u32");
    sign_vote_for_view(vote, chain, topology, keypairs);
}

