#[tokio::test(flavor = "current_thread")]
async fn rbc_session_ttl_prunes_stale_sessions() {
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.rbc_session_ttl = Duration::from_secs(1);
    let mut harness = test_actor_harness_with_config(1, consensus_cfg, None).await;
    let key = session_key();
    let payload = b"payload".to_vec();
    let payload_hash = Hash::new(&payload);
    let session =
        Actor::build_rbc_session_from_payload(&payload, payload_hash, 1024, 0).expect("session");

    harness
        .actor
        .subsystems
        .da_rbc
        .rbc
        .sessions
        .insert(key, session.clone());
    let roster = harness.actor.effective_commit_topology();
    harness
        .actor
        .record_rbc_session_roster(key, roster, super::RbcRosterSource::Network);
    harness.actor.update_rbc_status_entry(key, &session, false);

    let stale_time = SystemTime::now() - Duration::from_secs(2);
    harness.actor.subsystems.da_rbc.rbc.status_handle.update_at(
        key,
        session.total_chunks(),
        session.received_chunks(),
        u64::try_from(session.ready_signatures.len()).unwrap_or(u64::MAX),
        session.delivered,
        session.payload_hash(),
        stale_time,
        session.recovered_from_disk(),
    );

    assert!(harness.actor.prune_stale_rbc_sessions(SystemTime::now()));
    assert!(
        !harness
            .actor
            .subsystems
            .da_rbc
            .rbc
            .sessions
            .contains_key(&key)
    );
    assert!(
        harness
            .actor
            .subsystems
            .da_rbc
            .rbc
            .status_handle
            .get(&key)
            .is_none()
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn seed_rbc_session_flushes_pending_ready() {
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.rbc_chunk_max_bytes = 1024;
    consensus_cfg.rbc_pending_max_chunks = 4;
    consensus_cfg.rbc_pending_max_bytes = 4096;
    let mut harness = test_actor_harness_with_config(1, consensus_cfg, None).await;

    let block = sample_block(1, 0, None);
    let block_hash = block.hash();
    let payload_bytes = super::proposals::block_payload_bytes(&block);
    let payload_hash = Hash::new(&payload_bytes);
    let height = block.header().height().get();
    let session_key = Actor::session_key(&block_hash, height, 0);
    let epoch = harness.actor.epoch_for_height(height);
    let session = Actor::build_rbc_session_from_payload(
        &payload_bytes,
        payload_hash,
        harness.actor.config.rbc_chunk_max_bytes,
        epoch,
    )
    .expect("rbc session");
    let roster = harness.actor.effective_commit_topology();
    harness
        .actor
        .record_rbc_session_roster(session_key, roster, super::RbcRosterSource::Network);
    let mut ready = harness
        .actor
        .build_rbc_ready(session_key, &session)
        .expect("ready");
    ready.sender = ready.sender.saturating_add(1);

    harness
        .actor
        .handle_rbc_ready(ready)
        .expect("pending ready");
    let pending = harness
        .actor
        .subsystems
        .da_rbc
        .rbc
        .pending
        .get(&session_key)
        .expect("pending ready stash");
    assert_eq!(pending.ready.len(), 1);
    assert!(
        harness
            .actor
            .subsystems
            .da_rbc
            .rbc
            .pending
            .contains_key(&session_key),
        "pending READY should exist before seeding"
    );

    harness
        .actor
        .seed_rbc_session_from_block(session_key, &block, payload_hash)
        .expect("seed rbc session");

    assert!(
        !harness
            .actor
            .subsystems
            .da_rbc
            .rbc
            .pending
            .contains_key(&session_key),
        "seeding RBC session should flush pending READY messages"
    );

    harness.shutdown.send();
}

