#[tokio::test(flavor = "current_thread")]
async fn roster_for_vote_falls_back_to_prev_commit_topology_without_snapshot() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let height = 2u64;
    let block_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xC2; Hash::LENGTH]));

    let roster = actor.effective_commit_topology();
    let local_peer_id = actor.common_config.peer.id();
    let removed_peer = roster
        .iter()
        .find(|peer| *peer != local_peer_id)
        .cloned()
        .expect("non-local roster entry");

    let mut roster_new = roster.clone();
    roster_new.retain(|peer| peer != &removed_peer);
    {
        let mut prev_block = actor.state.prev_commit_topology.block();
        prev_block.mutate_vec(|vec| *vec = roster.clone());
        prev_block.commit();
    }
    {
        let mut topo_block = actor.state.commit_topology.block();
        topo_block.mutate_vec(|vec| *vec = roster_new);
        topo_block.commit();
    }
    {
        let mut hashes = actor.state.block_hashes.block();
        hashes.push(HashOf::from_untyped_unchecked(Hash::prehashed(
            [0xC1; Hash::LENGTH],
        )));
        hashes.push(block_hash);
        hashes.commit_for_tests();
    }

    let qc_roster = actor.roster_for_vote(block_hash, height, 0);
    assert_eq!(
        qc_roster, roster,
        "committed height should fall back to the previous commit topology"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn new_view_votes_use_commit_qc_history_for_height() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let block_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x00; Hash::LENGTH]));
    let active_roster = actor.effective_commit_topology();
    assert!(
        active_roster.len() >= 2,
        "test needs at least two validators to rotate roster"
    );

    let mut history_roster = active_roster.clone();
    history_roster.rotate_left(1);
    assert_ne!(
        history_roster, active_roster,
        "roster rotation should change order"
    );

    let mut signers = BTreeSet::new();
    for idx in 0..history_roster.len() {
        signers.insert(ValidatorIndex::try_from(idx).expect("signer index fits"));
    }
    let signers_bitmap = super::build_signers_bitmap(&signers, history_roster.len());
    let topology = super::network_topology::Topology::new(history_roster.clone());
    let bls_aggregate_signature = aggregate_signature_for_bitmap(
        &actor.common_config.chain,
        PERMISSIONED_TAG,
        Phase::Commit,
        block_hash,
        2,
        0,
        0,
        &signers_bitmap,
        &topology,
        &harness.key_pairs,
    );
    let commit_qc = Qc {
        phase: Phase::Commit,
        subject_block_hash: block_hash,
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height: 2,
        view: 0,
        epoch: 0,
        mode_tag: PERMISSIONED_TAG.to_string(),
        highest_qc: None,
        validator_set_hash: HashOf::new(&history_roster),
        validator_set_hash_version: VALIDATOR_SET_HASH_VERSION_V1,
        validator_set: history_roster.clone(),
        aggregate: QcAggregate {
            signers_bitmap,
            bls_aggregate_signature,
        },
    };
    status::record_commit_qc(commit_qc);

    let derived_roster = {
        let mut topology = super::network_topology::Topology::new(history_roster.clone());
        topology.block_committed(history_roster.clone(), block_hash);
        topology.as_ref().to_vec()
    };

    let highest_qc = crate::sumeragi::consensus::QcRef {
        height: 2,
        view: 0,
        epoch: 0,
        subject_block_hash: block_hash,
        phase: Phase::Commit,
    };
    let mut vote = crate::sumeragi::consensus::Vote {
        phase: Phase::NewView,
        block_hash,
        parent_state_root: iroha_crypto::Hash::prehashed([0u8; iroha_crypto::Hash::LENGTH]),
        post_state_root: iroha_crypto::Hash::prehashed([0u8; iroha_crypto::Hash::LENGTH]),
        height: 3,
        view: 1,
        epoch: 0,
        highest_qc: Some(highest_qc),
        signer: 0,
        bls_sig: Vec::new(),
    };
    let topology = super::network_topology::Topology::new(derived_roster);
    sign_vote_for_view(
        &mut vote,
        &actor.common_config.chain,
        &topology,
        &harness.key_pairs,
    );

    actor.handle_vote(vote.clone());

    let key = (
        Phase::NewView,
        vote.height,
        vote.view,
        vote.epoch,
        vote.signer,
    );
    assert!(
        actor.vote_log.contains_key(&key),
        "new-view votes should be validated against the commit certificate-derived roster"
    );

    status::reset_commit_certs_for_tests();
    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn new_view_tracker_counts_local_with_rotated_indices() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let committed_height = actor.state.view().height() as u64;
    let height = committed_height.saturating_add(1);
    let view = 1;
    let epoch = actor.epoch_for_height(height);
    let block_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x5A; Hash::LENGTH]));
    let highest_qc = QcHeaderRef {
        subject_block_hash: block_hash,
        height: committed_height,
        view: 0,
        epoch,
        phase: Phase::Commit,
    };

    let topology = super::network_topology::Topology::new(actor.effective_commit_topology());
    let local_idx = actor
        .local_validator_index_for_topology(&topology)
        .expect("local peer in topology");
    let rotated = super::topology_for_view(&topology, height, view, PERMISSIONED_TAG, None);
    let signer_idx = usize::try_from(local_idx).expect("local index fits usize");
    let rotated_peer = rotated
        .as_ref()
        .get(signer_idx)
        .expect("rotated peer available");
    assert_ne!(
        rotated_peer,
        actor.common_config.peer.id(),
        "rotated signer should be remote"
    );

    let mut vote = crate::sumeragi::consensus::Vote {
        phase: Phase::NewView,
        block_hash,
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height,
        view,
        epoch,
        highest_qc: Some(highest_qc),
        signer: local_idx,
        bls_sig: Vec::new(),
    };
    sign_vote_for_view(
        &mut vote,
        &actor.common_config.chain,
        &topology,
        &harness.key_pairs,
    );
    actor.handle_vote(vote);

    let counted = actor.subsystems.propose.new_view_tracker.count_with_local(
        height,
        view,
        Some(actor.common_config.peer.id()),
    );
    assert_eq!(
        counted, 2,
        "local peer should count toward quorum even when signer index matches local index"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn new_view_vote_rejects_mismatched_highest_block_hash() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let committed_height = actor.state.view().height() as u64;
    let height = committed_height.saturating_add(1);
    let view = 0;
    let epoch = actor.epoch_for_height(height);
    let topology = super::network_topology::Topology::new(actor.effective_commit_topology());
    let signature_topology =
        super::topology_for_view(&topology, height, view, PERMISSIONED_TAG, None);
    let signer = actor
        .local_validator_index_for_topology(&signature_topology)
        .expect("local peer in topology");
    let mut highest_qc = sample_qc_ref(committed_height, 0);
    highest_qc.phase = Phase::Commit;
    let wrong_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xA5; Hash::LENGTH]));

    let mut vote = crate::sumeragi::consensus::Vote {
        phase: Phase::NewView,
        block_hash: wrong_hash,
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height,
        view,
        epoch,
        highest_qc: Some(highest_qc),
        signer,
        bls_sig: Vec::new(),
    };
    sign_vote_for_view(
        &mut vote,
        &actor.common_config.chain,
        &topology,
        &harness.key_pairs,
    );
    actor.handle_vote(vote);

    let key = (Phase::NewView, height, view, epoch, signer);
    assert!(
        actor.vote_log.get(&key).is_none(),
        "mismatched highest hash should not be recorded"
    );
    assert_eq!(
        actor
            .subsystems
            .propose
            .new_view_tracker
            .count(height, view),
        0,
        "mismatched highest hash should not advance NEW_VIEW tracking"
    );

    harness.shutdown.send();
}

