#[tokio::test(flavor = "multi_thread", worker_threads = 2)]
async fn block_created_requests_missing_parent_on_height_gap() {
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Permissioned;
    let mut harness = test_actor_harness_with_config(4, consensus_cfg, None).await;
    let actor = &mut harness.actor;

    let state_height = actor.state.view().height() as u64;
    let block_height = state_height.saturating_add(2);
    let mut missing_parent =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x45; Hash::LENGTH]));
    if actor.block_known_locally(missing_parent) {
        missing_parent =
            HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x46; Hash::LENGTH]));
    }
    let block = sample_block(block_height, 0, Some(missing_parent));
    let block_hash = block.hash();

    actor
        .handle_block_created(super::message::BlockCreated { block })
        .expect("handle BlockCreated");

    assert!(
        actor.pending.pending_blocks.contains_key(&block_hash),
        "BlockCreated should store the pending block"
    );
    let request = actor
        .pending
        .missing_block_requests
        .get(&missing_parent)
        .expect("missing-parent request should be recorded");
    assert_eq!(
        request.height,
        block_height.saturating_sub(1),
        "missing-parent request should track parent height"
    );
    let expected_window = actor.quorum_timeout(actor.runtime_da_enabled());
    assert_eq!(
        request.priority,
        super::MissingBlockPriority::Background,
        "missing-parent fetch should be treated as background priority"
    );
    assert_eq!(
        request.view_change_window,
        Some(expected_window),
        "gap-1 missing-parent requests should allow view-change after quorum timeout"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn block_created_uses_snapshot_roster_for_missing_parent_when_active_empty() {
    let mut harness = test_actor_harness(1).await;
    let actor = &mut harness.actor;

    let state_height = actor.state.view().height() as u64;
    let block_height = state_height.saturating_add(2);
    let mut missing_parent =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x61; Hash::LENGTH]));
    if actor.block_known_locally(missing_parent) {
        missing_parent =
            HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x62; Hash::LENGTH]));
    }
    let block = sample_block(block_height, 0, Some(missing_parent));
    let block_hash = block.hash();
    let roster = vec![actor.common_config.peer.id().clone()];
    let topology = super::network_topology::Topology::new(roster.clone());
    let signers_bitmap = vec![0b0000_0001];
    let chain = actor.common_config.chain.clone();
    let keypairs = vec![actor.common_config.key_pair.clone()];
    let bls_aggregate_signature = aggregate_signature_for_bitmap(
        &chain,
        PERMISSIONED_TAG,
        Phase::Commit,
        block_hash,
        block_height,
        0,
        0,
        &signers_bitmap,
        &topology,
        &keypairs,
    );
    let checkpoint_signature = aggregate_vote_signature_for_bitmap(
        &chain,
        PERMISSIONED_TAG,
        block_hash,
        block_height,
        0,
        0,
        &signers_bitmap,
        &topology,
        &keypairs,
    );
    let commit_qc = Qc {
        phase: Phase::Commit,
        subject_block_hash: block_hash,
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height: block_height,
        view: 0,
        epoch: 0,
        mode_tag: PERMISSIONED_TAG.to_string(),
        highest_qc: None,
        validator_set_hash: HashOf::new(&roster),
        validator_set_hash_version: VALIDATOR_SET_HASH_VERSION_V1,
        validator_set: roster.clone(),
        aggregate: QcAggregate {
            signers_bitmap: signers_bitmap.clone(),
            bls_aggregate_signature,
        },
    };
    let checkpoint = ValidatorSetCheckpoint::new(
        block_height,
        block_hash,
        roster,
        signers_bitmap,
        checkpoint_signature,
        VALIDATOR_SET_HASH_VERSION_V1,
        None,
    );

    {
        let state = Arc::get_mut(&mut actor.state).expect("state uniquely held");
        let mut journal = state.commit_roster_journal.write();
        journal.upsert(commit_qc, checkpoint, None);
        state.commit_topology.mutate_vec(|vec| vec.clear());
        state.prev_commit_topology.mutate_vec(|vec| vec.clear());
        let mut world_block = state.world.block();
        world_block.peers.get_mut().clear();
        world_block.commit();
    }

    actor
        .handle_block_created(super::message::BlockCreated { block })
        .expect("handle BlockCreated");

    assert!(
        actor
            .pending
            .missing_block_requests
            .contains_key(&missing_parent),
        "missing-parent fetch should be scheduled when a snapshot roster is available"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn validation_defers_block_ahead_of_local_height() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let state_height = actor.state.view().height() as u64;
    let block_height = state_height.saturating_add(2);
    let mut missing_parent =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x55; Hash::LENGTH]));
    if actor.block_known_locally(missing_parent) {
        missing_parent =
            HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x56; Hash::LENGTH]));
    }
    let block = sample_block(block_height, 0, Some(missing_parent));
    let block_hash = block.hash();
    let payload_bytes = super::proposals::block_payload_bytes(&block);
    let payload_hash = Hash::new(&payload_bytes);
    let view = u64::from(block.header().view_change_index());

    actor.pending.pending_blocks.insert(
        block_hash,
        PendingBlock::new(block, payload_hash, block_height, view),
    );

    let commit_topology = actor.effective_commit_topology();
    let outcome = actor.validate_pending_block_for_voting(block_hash, &commit_topology);
    assert!(
        matches!(outcome, ValidationGateOutcome::Deferred),
        "blocks ahead of local height should defer validation"
    );
    let pending = actor
        .pending
        .pending_blocks
        .get(&block_hash)
        .expect("pending block retained");
    assert_eq!(
        pending.validation_status,
        ValidationStatus::Pending,
        "deferred validation should not mark block invalid"
    );
    assert!(
        actor
            .pending
            .missing_block_requests
            .contains_key(&missing_parent),
        "validation should request missing parent block"
    );

    harness.shutdown.send();
}

