#[test]
fn validate_block_sync_qc_accepts_npos_rotated_signers_across_views() {
    let chain: ChainId = "block-sync-npos-views".parse().expect("chain id parses");
    let (keypairs, topology) = sample_bls_topology(4);
    let seed = [0x5A; 32];
    let height = 8u64;
    let block_view = 0u64;
    let base_leader = topology.leader_index_prf(seed, height, block_view);
    let mut qc_view = None;
    for candidate in 1..20u64 {
        if topology.leader_index_prf(seed, height, candidate) != base_leader {
            qc_view = Some(candidate);
            break;
        }
    }
    let qc_view = qc_view.expect("expected view with different leader rotation");

    let block_topology =
        super::topology_for_view(&topology, height, block_view, super::NPOS_TAG, Some(seed));
    let qc_topology =
        super::topology_for_view(&topology, height, qc_view, super::NPOS_TAG, Some(seed));

    let canonical_peers: Vec<_> = topology.as_ref().iter().take(3).cloned().collect();
    let block_signers: BTreeSet<ValidatorIndex> = canonical_peers
        .iter()
        .filter_map(|peer| {
            block_topology
                .as_ref()
                .iter()
                .position(|p| p == peer)
                .and_then(|idx| ValidatorIndex::try_from(idx).ok())
        })
        .collect();
    let qc_view_signers: BTreeSet<ValidatorIndex> = canonical_peers
        .iter()
        .filter_map(|peer| {
            qc_topology
                .as_ref()
                .iter()
                .position(|p| p == peer)
                .and_then(|idx| ValidatorIndex::try_from(idx).ok())
        })
        .collect();
    let canonical_signers: BTreeSet<ValidatorIndex> = canonical_peers
        .iter()
        .filter_map(|peer| {
            topology
                .as_ref()
                .iter()
                .position(|p| p == peer)
                .and_then(|idx| ValidatorIndex::try_from(idx).ok())
        })
        .collect();

    assert_eq!(block_signers.len(), 3);
    assert_eq!(qc_view_signers.len(), 3);
    assert_eq!(canonical_signers.len(), 3);
    assert_ne!(
        block_signers, qc_view_signers,
        "rotation should shift signer indices"
    );

    let block_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x74; Hash::LENGTH]));
    let signers_bitmap = super::build_signers_bitmap(&canonical_signers, topology.as_ref().len());
    let validator_set = topology.as_ref().to_vec();
    let qc_stub = crate::sumeragi::consensus::Qc {
        phase: crate::sumeragi::consensus::Phase::Commit,
        subject_block_hash: block_hash,
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height,
        view: qc_view,
        epoch: 0,
        mode_tag: super::NPOS_TAG.to_string(),
        highest_qc: None,
        validator_set_hash: HashOf::new(&validator_set),
        validator_set_hash_version: VALIDATOR_SET_HASH_VERSION_V1,
        validator_set,
        aggregate: crate::sumeragi::consensus::QcAggregate {
            signers_bitmap: Vec::new(),
            bls_aggregate_signature: Vec::new(),
        },
    };
    let preimage = super::qc_bls_preimage(&qc_stub, &chain, super::NPOS_TAG);
    let mut signatures = Vec::with_capacity(canonical_signers.len());
    for signer in &canonical_signers {
        let idx = usize::try_from(*signer).expect("signer fits usize");
        let peer = topology
            .as_ref()
            .get(idx)
            .expect("signer present in topology");
        let kp = keypairs
            .iter()
            .find(|kp| kp.public_key() == peer.public_key())
            .expect("matching keypair for signer");
        let sig = Signature::new(kp.private_key(), &preimage);
        signatures.push(sig.payload().to_vec());
    }
    let sig_refs: Vec<&[u8]> = signatures.iter().map(Vec::as_slice).collect();
    let aggregate_signature =
        iroha_crypto::bls_normal_aggregate_signatures(&sig_refs).expect("aggregate succeeds");

    let qc = crate::sumeragi::consensus::Qc {
        aggregate: crate::sumeragi::consensus::QcAggregate {
            signers_bitmap,
            bls_aggregate_signature: aggregate_signature,
        },
        ..qc_stub
    };

    let result = super::validate_block_sync_qc(
        &qc,
        &topology,
        &block_signers,
        block_view,
        &chain,
        ConsensusMode::Permissioned,
        None,
        super::NPOS_TAG,
        Some(seed),
    )
    .expect("block sync QC should validate across NPoS view rotations");
    assert_eq!(result.0.len(), 3);
    assert_eq!(result.1, 3);
}

#[test]
fn validated_block_signers_accept_trimmed_commit_roles() {
    let kp_leader = KeyPair::random_with_algorithm(Algorithm::BlsNormal);
    let kp_validator = KeyPair::random_with_algorithm(Algorithm::BlsNormal);
    let kp_proxy = KeyPair::random_with_algorithm(Algorithm::BlsNormal);
    let topology = super::network_topology::Topology::new(vec![
        PeerId::new(kp_leader.public_key().clone()),
        PeerId::new(kp_validator.public_key().clone()),
        PeerId::new(kp_proxy.public_key().clone()),
    ]);

    let mut block = super::ValidBlock::new_dummy(kp_leader.private_key());
    block.sign(&kp_validator, &topology);
    let block: SignedBlock = block.into();
    let state = State::new_for_testing(
        World::new(),
        Kura::blank_kura_for_testing(),
        LiveQueryStore::start_test(),
    );

    let signers = super::validated_block_signers(
        &block,
        &topology,
        &state.view(),
        super::PERMISSIONED_TAG,
        None,
    )
    .expect("trimmed commit signatures should still be parsed");
    assert_eq!(signers.len(), 2);
    assert!(signers.contains(&ValidatorIndex::try_from(0u32).expect("validator index parses")));
    assert!(signers.contains(&ValidatorIndex::try_from(1u32).expect("validator index parses")));
    assert!(!signers.contains(&ValidatorIndex::try_from(2u32).expect("validator index parses")));
}

