#[tokio::test(flavor = "current_thread")]
async fn da_gate_context_does_not_block_quorum_reschedule() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;
    let view = actor.state.view();
    let height = view.height() as u64 + 1;
    let parent = view.latest_block_hash();
    drop(view);

    let block = sample_block(height, 0, parent);
    let block_hash = block.hash();
    let payload_bytes = super::proposals::block_payload_bytes(&block);
    let payload_hash = Hash::new(&payload_bytes);
    let view_idx = u64::from(block.header().view_change_index());
    actor.pending.pending_blocks.insert(
        block_hash,
        PendingBlock::new(block, payload_hash, height, view_idx),
    );
    let quorum_timeout = actor.quorum_timeout(true);
    {
        let pending = actor
            .pending
            .pending_blocks
            .get_mut(&block_hash)
            .expect("pending block");
        pending.validation_status = ValidationStatus::Valid;
        pending.last_gate = Some(GateReason::ManifestGuard {
            lane: LaneId::new(1),
            epoch: 0,
            sequence: 0,
            kind: ManifestGateKind::Missing,
        });
        pending.inserted_at = Instant::now() - quorum_timeout - Duration::from_millis(1);
    }

    assert!(
        actor.reschedule_stale_pending_blocks(),
        "DA gate context should not block quorum reschedule"
    );
    let pending_after = actor
        .pending
        .pending_blocks
        .get(&block_hash)
        .expect("pending retained");
    assert!(
        pending_after.last_quorum_reschedule.is_some(),
        "pending should be quorum-rescheduled even while availability is missing"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn reschedule_stale_pending_blocks_skips_empty_roster() {
    let mut harness = test_actor_harness(1).await;
    let actor = &mut harness.actor;
    let view = actor.state.view();
    let height = view.height() as u64 + 1;
    let parent = view.latest_block_hash();
    drop(view);

    {
        let state = Arc::get_mut(&mut actor.state).expect("state uniquely held");
        state.commit_topology.mutate_vec(|vec| vec.clear());
        state.prev_commit_topology.mutate_vec(|vec| vec.clear());
        let mut block = state.world.block();
        block.peers.get_mut().clear();
        block.commit();
    }

    let block = sample_block(height, 0, parent);
    let block_hash = block.hash();
    let payload_bytes = super::proposals::block_payload_bytes(&block);
    let payload_hash = Hash::new(&payload_bytes);
    let view_idx = u64::from(block.header().view_change_index());
    actor.pending.pending_blocks.insert(
        block_hash,
        PendingBlock::new(block, payload_hash, height, view_idx),
    );

    assert!(
        !actor.reschedule_stale_pending_blocks(),
        "empty roster should skip reschedule"
    );
    assert!(
        actor.pending.pending_blocks.contains_key(&block_hash),
        "pending block should be retained when roster is empty"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn reschedule_stale_pending_blocks_targets_snapshot_roster() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;
    let view = actor.state.view();
    let height = view.height() as u64 + 1;
    let parent = view.latest_block_hash();
    drop(view);

    let block = sample_block(height, 0, parent);
    let block_hash = block.hash();
    let payload_bytes = super::proposals::block_payload_bytes(&block);
    let payload_hash = Hash::new(&payload_bytes);
    let view_idx = u64::from(block.header().view_change_index());
    let quorum_timeout = actor.quorum_timeout(actor.runtime_da_enabled());
    let mut pending = PendingBlock::new(block, payload_hash, height, view_idx);
    pending.inserted_at = Instant::now() - quorum_timeout - Duration::from_millis(1);
    actor.pending.pending_blocks.insert(block_hash, pending);

    let mut snapshot_roster = actor.effective_commit_topology();
    let local_peer = actor.common_config.peer.id().clone();
    let removed_peer = snapshot_roster
        .iter()
        .find(|peer| *peer != &local_peer)
        .cloned()
        .expect("non-local roster entry");
    snapshot_roster.retain(|peer| peer != &removed_peer);
    assert!(
        snapshot_roster.contains(&local_peer),
        "snapshot roster must include local peer"
    );

    let topology = super::network_topology::Topology::new(snapshot_roster.clone());
    let signers: BTreeSet<ValidatorIndex> = (0..snapshot_roster.len())
        .map(|idx| ValidatorIndex::try_from(idx).expect("validator index fits"))
        .collect();
    let signers_bitmap = super::build_signers_bitmap(&signers, snapshot_roster.len());
    let commit_qc = qc_with_bitmap(
        &actor.common_config.chain,
        block_hash,
        height,
        view_idx,
        0,
        signers_bitmap.clone(),
        Phase::Commit,
        &topology,
        &harness.key_pairs,
    );
    let checkpoint_signature = aggregate_vote_signature_for_bitmap(
        &actor.common_config.chain,
        PERMISSIONED_TAG,
        block_hash,
        height,
        view_idx,
        0,
        &signers_bitmap,
        &topology,
        &harness.key_pairs,
    );
    let checkpoint = ValidatorSetCheckpoint::new(
        height,
        block_hash,
        snapshot_roster.clone(),
        signers_bitmap,
        checkpoint_signature,
        VALIDATOR_SET_HASH_VERSION_V1,
        None,
    );
    {
        let mut journal = actor.state.commit_roster_journal.write();
        journal.upsert(commit_qc, checkpoint, None);
    }

    assert!(
        actor.reschedule_stale_pending_blocks(),
        "pending block should be rescheduled"
    );

    let expected_targets: BTreeSet<_> = snapshot_roster
        .iter()
        .filter(|peer| *peer != &local_peer)
        .cloned()
        .collect();
    let mut targets = BTreeSet::new();
    for post in harness.background_rx.try_iter() {
        let BackgroundPost::Post { peer, msg, .. } = post else {
            continue;
        };
        if let BlockMessage::BlockCreated(created) = msg {
            if created.block.hash() == block_hash {
                targets.insert(peer);
            }
        }
    }
    assert_eq!(
        targets, expected_targets,
        "reschedule should rebroadcast to the snapshot roster"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn reschedule_stale_pending_blocks_skips_when_commit_qc_cached() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;
    let view = actor.state.view();
    let height = view.height() as u64 + 1;
    let parent = view.latest_block_hash();
    drop(view);

    let block = sample_block(height, 0, parent);
    let block_hash = block.hash();
    let payload_bytes = super::proposals::block_payload_bytes(&block);
    let payload_hash = Hash::new(&payload_bytes);
    let view_idx = u64::from(block.header().view_change_index());
    let mut pending = PendingBlock::new(block, payload_hash, height, view_idx);
    let quorum_timeout = actor.quorum_timeout(actor.runtime_da_enabled());
    pending.inserted_at = Instant::now() - quorum_timeout - Duration::from_millis(1);
    actor.pending.pending_blocks.insert(block_hash, pending);

    let commit_topology = actor.effective_commit_topology();
    let topology = super::network_topology::Topology::new(commit_topology.clone());
    let epoch = actor.epoch_for_height(height);
    let signers: BTreeSet<ValidatorIndex> = (0..commit_topology.len())
        .map(|idx| ValidatorIndex::try_from(idx).expect("validator index fits"))
        .collect();
    let signers_bitmap = super::build_signers_bitmap(&signers, commit_topology.len());
    let qc = qc_with_bitmap(
        &actor.common_config.chain,
        block_hash,
        height,
        view_idx,
        epoch,
        signers_bitmap,
        Phase::Commit,
        &topology,
        &harness.key_pairs,
    );
    actor
        .qc_cache
        .insert((Phase::Commit, block_hash, height, view_idx, epoch), qc);

    actor.reschedule_stale_pending_blocks();

    let pending_after = actor
        .pending
        .pending_blocks
        .get(&block_hash)
        .expect("pending retained");
    assert!(
        pending_after.last_quorum_reschedule.is_none(),
        "commit QC should prevent quorum reschedule"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn commit_pipeline_reschedules_without_da_gate_blocking() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;
    let view = actor.state.view();
    let height = view.height() as u64 + 1;
    let parent = view.latest_block_hash();
    drop(view);

    let block = sample_block(height, 0, parent);
    let block_hash = block.hash();
    let payload_bytes = super::proposals::block_payload_bytes(&block);
    let payload_hash = Hash::new(&payload_bytes);
    let view_idx = u64::from(block.header().view_change_index());
    actor.pending.pending_blocks.insert(
        block_hash,
        PendingBlock::new(block, payload_hash, height, view_idx),
    );
    let quorum_timeout = actor.quorum_timeout(true);
    let availability_timeout = actor.availability_timeout(quorum_timeout, true);
    {
        let pending = actor
            .pending
            .pending_blocks
            .get_mut(&block_hash)
            .expect("pending block");
        pending.validation_status = ValidationStatus::Valid;
        pending.inserted_at = Instant::now() - quorum_timeout - Duration::from_millis(1);
        pending.last_gate = Some(GateReason::ManifestGuard {
            lane: LaneId::new(2),
            epoch: 0,
            sequence: 1,
            kind: ManifestGateKind::Missing,
        });
    }
    assert!(
        quorum_timeout < availability_timeout,
        "availability timeout should exceed quorum timeout in DA mode"
    );

    actor.process_commit_candidates_with_trigger(CommitPipelineTrigger::Event);

    let pending_after = actor
        .pending
        .pending_blocks
        .get(&block_hash)
        .expect("pending retained");
    assert_eq!(
        pending_after.last_gate,
        Some(GateReason::MissingLocalData),
        "availability gate should record missing local data while rescheduling"
    );
    assert!(
        pending_after.last_quorum_reschedule.is_some(),
        "commit pipeline should reschedule even while availability is missing"
    );

    harness.shutdown.send();
}

#[test]
fn missing_quorum_stale_respects_timeout_and_vote_count() {
    let timeout = Duration::from_millis(500);
    assert!(!missing_quorum_stale(
        Duration::from_millis(100),
        timeout,
        false
    ));
    assert!(missing_quorum_stale(
        Duration::from_millis(600),
        timeout,
        false
    ));
    assert!(!missing_quorum_stale(
        Duration::from_millis(600),
        Duration::ZERO,
        false
    ));
    assert!(!missing_quorum_stale(
        Duration::from_millis(600),
        timeout,
        true
    ));
}

#[test]
fn prevote_quorum_stale_requires_phase_and_timeout() {
    let timeout = Duration::from_millis(200);
    assert!(prevote_quorum_stale(
        Some(crate::sumeragi::consensus::Phase::Prepare),
        Duration::from_millis(250),
        timeout
    ));
    assert!(!prevote_quorum_stale(
        Some(crate::sumeragi::consensus::Phase::Commit),
        Duration::from_millis(250),
        timeout
    ));
    assert!(!prevote_quorum_stale(
        Some(crate::sumeragi::consensus::Phase::Prepare),
        Duration::from_millis(150),
        timeout
    ));
}

#[test]
fn prevote_quorum_stale_rejects_zero_timeout() {
    assert!(!prevote_quorum_stale(
        Some(crate::sumeragi::consensus::Phase::Prepare),
        Duration::from_millis(400),
        Duration::ZERO
    ));
}

#[test]
fn precommit_vote_count_ignores_non_precommit_qc() {
    let validator_set: Vec<PeerId> = (0..4)
        .map(|_| {
            PeerId::new(
                KeyPair::random_with_algorithm(Algorithm::BlsNormal)
                    .public_key()
                    .clone(),
            )
        })
        .collect();
    let validator_set_hash = HashOf::new(&validator_set);
    let qc_prevote = crate::sumeragi::consensus::Qc {
        phase: crate::sumeragi::consensus::Phase::Prepare,
        subject_block_hash: HashOf::from_untyped_unchecked(Hash::prehashed([0xAB; 32])),
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height: 4,
        view: 2,
        epoch: 0,
        mode_tag: PERMISSIONED_TAG.to_string(),
        highest_qc: None,
        validator_set_hash: validator_set_hash.clone(),
        validator_set_hash_version: VALIDATOR_SET_HASH_VERSION_V1,
        validator_set: validator_set.clone(),
        aggregate: crate::sumeragi::consensus::QcAggregate {
            signers_bitmap: vec![0b1111],
            bls_aggregate_signature: Vec::new(),
        },
    };
    let qc_precommit = crate::sumeragi::consensus::Qc {
        phase: crate::sumeragi::consensus::Phase::Commit,
        subject_block_hash: HashOf::from_untyped_unchecked(Hash::prehashed([0xCD; 32])),
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height: 4,
        view: 2,
        epoch: 0,
        mode_tag: PERMISSIONED_TAG.to_string(),
        highest_qc: None,
        validator_set_hash,
        validator_set_hash_version: VALIDATOR_SET_HASH_VERSION_V1,
        validator_set,
        aggregate: crate::sumeragi::consensus::QcAggregate {
            signers_bitmap: vec![0b1111],
            bls_aggregate_signature: Vec::new(),
        },
    };
    assert_eq!(precommit_vote_count(&qc_prevote, 4), 0);
    assert_eq!(precommit_vote_count(&qc_precommit, 4), 4);
}

