fn heartbeat_block_for_state(
    state: &State,
    chain_id: &ChainId,
    height: u64,
    view: u32,
    parent: Option<HashOf<BlockHeader>>,
    signer_kp: &KeyPair,
    signer_idx: u64,
) -> SignedBlock {
    let (tx_params, policies, confidential_features) = {
        let view = state.view();
        let tx_params = view.world().parameters().transaction().clone();
        let policies = crate::da::proof_policy_bundle(&view.nexus.lane_config);
        let digest = compute_confidential_feature_digest(view.world(), &view.zk, height);
        let confidential_features = if digest.is_empty() {
            None
        } else {
            Some(digest)
        };
        (tx_params, policies, confidential_features)
    };
    let start_ms = height.saturating_sub(1);
    let (time_handle, time_source) = TimeSource::new_mock(Duration::from_millis(start_ms));
    let heartbeat_signer = KeyPair::random_with_algorithm(Algorithm::Ed25519);
    let heartbeat = crate::tx::build_heartbeat_transaction_with_time_source(
        chain_id.clone(),
        &heartbeat_signer,
        &tx_params,
        height,
        &time_source,
    );
    time_handle.advance(Duration::from_millis(1));
    let creation_time_ms =
        u64::try_from(time_source.get_unix_time().as_millis()).expect("creation time fits in u64");
    let header = BlockHeader {
        height: NonZeroU64::new(height).expect("block height must be non-zero"),
        prev_block_hash: parent,
        merkle_root: None,
        result_merkle_root: None,
        da_proof_policies_hash: None,
        da_commitments_hash: None,
        da_pin_intents_hash: None,
        creation_time_ms,
        view_change_index: view,
        confidential_features,
    };
    let mut builder = BlockBuilder::new(header);
    builder.push_transaction(heartbeat);
    builder.set_da_proof_policies(Some(policies));
    builder.build_with_signature(signer_idx, signer_kp.private_key())
}

#[test]
fn block_payload_bytes_ignores_results_and_extra_signatures() {
    let tx = sample_transaction();
    let mut block = block_with_txs(2, 0, None, vec![tx]);
    let baseline = super::proposals::block_payload_bytes(&block);

    let extra_key = KeyPair::random();
    let (_, extra_private) = extra_key.into_parts();
    let extra_sig = SignatureOf::from_hash(&extra_private, block.header().hash());
    block
        .add_signature(BlockSignature::new(1, extra_sig))
        .expect("add signature");

    let entry_hashes: Vec<_> = block
        .transactions_vec()
        .iter()
        .map(SignedTransaction::hash_as_entrypoint)
        .collect();
    block.set_transaction_results(
        Vec::new(),
        &entry_hashes,
        vec![TransactionResultInner::Ok(DataTriggerSequence::new())],
    );

    let updated = super::proposals::block_payload_bytes(&block);
    assert_eq!(baseline, updated);
}

#[test]
fn block_payload_bytes_ignores_missing_leader_signature() {
    let tx = sample_transaction();
    let mut block = block_with_txs(2, 0, None, vec![tx]);
    let baseline = super::proposals::block_payload_bytes(&block);

    let extra_key = KeyPair::random();
    let (_, extra_private) = extra_key.into_parts();
    let extra_sig = SignatureOf::from_hash(&extra_private, block.header().hash());
    let mut signatures = BTreeSet::new();
    signatures.insert(BlockSignature::new(1, extra_sig));
    block
        .replace_signatures(signatures)
        .expect("replace signatures");

    let updated = super::proposals::block_payload_bytes(&block);
    assert_eq!(baseline, updated);
}

fn sample_transaction() -> SignedTransaction {
    let chain: ChainId = "test-chain".parse().expect("chain id");
    let key_pair = KeyPair::random();
    let (_, private_key) = key_pair.clone().into_parts();
    let authority = AccountId::new(
        "wonderland".parse().expect("domain id"),
        key_pair.public_key().clone(),
    );
    let domain = Domain::new("wonderland".parse().expect("domain id"));
    let register: InstructionBox = Register::domain(domain).into();

    TransactionBuilder::new(chain, authority)
        .with_instructions([register])
        .sign(&private_key)
}

