#[tokio::test(flavor = "current_thread")]
async fn conflicting_vote_does_not_override_first() {
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Permissioned;
    let mut harness = test_actor_harness_with_config(4, consensus_cfg, None).await;
    let actor = &mut harness.actor;
    let committed_height = u64::try_from(actor.state.view().height()).unwrap_or(0);
    let height = committed_height.saturating_add(1);
    let view = 0;
    let epoch = actor.current_epoch();
    let chain_id = actor.chain_id.clone();
    let topology = super::network_topology::Topology::new(actor.effective_commit_topology());

    let block_hash_a =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xB1; Hash::LENGTH]));
    let block_hash_b =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xB2; Hash::LENGTH]));

    let mut vote_a = crate::sumeragi::consensus::Vote {
        phase: crate::sumeragi::consensus::Phase::Commit,
        block_hash: block_hash_a,
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height,
        view,
        epoch,
        highest_qc: None,
        signer: 0,
        bls_sig: Vec::new(),
    };
    sign_vote_for_view(&mut vote_a, &chain_id, &topology, &harness.key_pairs);
    actor.handle_vote(vote_a.clone());

    let mut vote_b = crate::sumeragi::consensus::Vote {
        phase: crate::sumeragi::consensus::Phase::Commit,
        block_hash: block_hash_b,
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height,
        view,
        epoch,
        highest_qc: None,
        signer: 0,
        bls_sig: Vec::new(),
    };
    sign_vote_for_view(&mut vote_b, &chain_id, &topology, &harness.key_pairs);
    actor.handle_vote(vote_b);

    let key = (
        crate::sumeragi::consensus::Phase::Commit,
        height,
        view,
        epoch,
        0,
    );
    let stored = actor.vote_log.get(&key).expect("vote recorded");
    assert_eq!(
        stored.block_hash, block_hash_a,
        "conflicting vote should not override the first vote"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn commit_qc_uses_exec_roots_from_view_votes() {
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Permissioned;
    let mut harness = test_actor_harness_with_config(4, consensus_cfg, None).await;
    let actor = &mut harness.actor;
    let committed_height = u64::try_from(actor.state.view().height()).unwrap_or(0);
    let height = committed_height.saturating_add(1);
    let view = 1u64;
    let epoch = actor.epoch_for_height(height);
    let chain_id = actor.chain_id.clone();
    let topology = super::network_topology::Topology::new(actor.effective_commit_topology());

    let block = block_with_txs(
        height,
        u32::try_from(view).expect("view fits u32"),
        None,
        vec![sample_transaction()],
    );
    let block_hash = block.hash();
    let payload_hash = Hash::new(&super::proposals::block_payload_bytes(&block));
    actor.pending.pending_blocks.insert(
        block_hash,
        PendingBlock::new(block, payload_hash, height, view),
    );
    actor.locked_qc = None;

    let signature_topology =
        super::topology_for_view(&topology, height, view, super::PERMISSIONED_TAG, None);
    let required = signature_topology.min_votes_for_commit().max(1);
    let parent_state_root = Hash::prehashed([0x11; 32]);
    let post_state_root = Hash::prehashed([0x22; 32]);

    for (idx, _) in signature_topology
        .as_ref()
        .iter()
        .enumerate()
        .take(required)
    {
        let mut vote = crate::sumeragi::consensus::Vote {
            phase: crate::sumeragi::consensus::Phase::Commit,
            block_hash,
            parent_state_root,
            post_state_root,
            height,
            view,
            epoch,
            highest_qc: None,
            signer: ValidatorIndex::try_from(idx).expect("signer index fits"),
            bls_sig: Vec::new(),
        };
        sign_vote_for_view(&mut vote, &chain_id, &topology, &harness.key_pairs);
        actor.handle_vote(vote);
    }

    let key = (
        crate::sumeragi::consensus::Phase::Commit,
        block_hash,
        height,
        view,
        epoch,
    );
    let qc = actor
        .qc_cache
        .get(&key)
        .expect("QC formed from view-aligned votes");
    assert_eq!(qc.parent_state_root, parent_state_root);
    assert_eq!(qc.post_state_root, post_state_root);

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
