#[tokio::test(flavor = "current_thread")]
async fn pending_roster_activation_applies_at_activation_height_during_catchup() {
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Npos;
    consensus_cfg.da_enabled = true;
    consensus_cfg.epoch_length_blocks = 10;

    let mut harness = test_actor_harness_with_config(4, consensus_cfg, None).await;
    let actor = &mut harness.actor;

    let old_roster = actor.effective_commit_topology();
    let mut new_roster = old_roster.clone();
    new_roster.pop();
    assert!(
        new_roster.len() < old_roster.len(),
        "test roster should shrink"
    );

    let activate_at = 12u64;
    actor.pending_roster_activation = Some((activate_at, new_roster.clone()));
    actor.last_committed_height = 8;
    actor.block_count.0 = 8;

    let state = Arc::get_mut(&mut actor.state).expect("state uniquely held");
    for idx in 1_u8..=12 {
        let hash = HashOf::from_untyped_unchecked(Hash::prehashed([idx; Hash::LENGTH]));
        state.push_block_hash_for_testing(hash);
    }

    assert!(actor.poll_committed_blocks(), "commits should be processed");

    let view = actor.state.view();
    let record = view.world().vrf_epochs().get(&0).expect("epoch record");
    assert_eq!(
        record.roster_len,
        u32::try_from(old_roster.len()).unwrap_or(u32::MAX),
        "epoch snapshot should use pre-activation roster during catch-up"
    );
    assert_eq!(
        actor.effective_commit_topology(),
        new_roster,
        "commit topology should activate at or after the activation height"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn vrf_snapshot_uses_epoch_manager_params() {
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Npos;
    consensus_cfg.da_enabled = true;
    consensus_cfg.epoch_length_blocks = 10;
    consensus_cfg.vrf_commit_deadline_offset = 3;
    consensus_cfg.vrf_reveal_deadline_offset = 7;

    let mut harness = test_actor_harness_with_config(4, consensus_cfg, None).await;
    let roster_len = harness.actor.effective_commit_topology().len();
    let snapshot = {
        let manager = harness
            .actor
            .epoch_manager
            .as_mut()
            .expect("epoch manager available");
        manager.set_params(12, 4, 9);
        manager.snapshot_current_epoch(u32::try_from(roster_len).unwrap_or(0), 1)
    };

    let record = harness.actor.snapshot_to_vrf_record(snapshot, false, None);
    assert_eq!(record.epoch_length, 12);
    assert_eq!(record.commit_deadline_offset, 4);
    assert_eq!(record.reveal_deadline_offset, 9);
}

#[test]
fn pending_rbc_chunk_eviction_records_drop_counts() {
    let now = Instant::now();
    let mut pending = PendingRbcMessages::new(now);
    let chunk_a = sample_chunk_with_len(0, 4);
    let chunk_b = sample_chunk_with_len(1, 6);

    match pending.push_chunk_capped(chunk_a, 1, 8, now) {
        PendingChunkOutcome::Inserted {
            pending_chunks,
            evicted_chunks,
            ..
        } => {
            assert_eq!(pending_chunks, 1);
            assert_eq!(evicted_chunks, 0);
        }
        other => panic!("unexpected outcome: {other:?}"),
    }

    match pending.push_chunk_capped(chunk_b, 1, 8, now) {
        PendingChunkOutcome::Inserted {
            pending_chunks,
            pending_bytes,
            evicted_chunks,
            evicted_bytes,
        } => {
            assert_eq!(pending_chunks, 1);
            assert_eq!(pending_bytes, 6);
            assert_eq!(evicted_chunks, 1);
            assert_eq!(evicted_bytes, 4);
        }
        other => panic!("unexpected outcome: {other:?}"),
    }

    let (dropped_chunks, dropped_bytes) = pending.dropped_counts();
    assert_eq!(dropped_chunks, 1);
    assert_eq!(dropped_bytes, 4);
}

#[test]
fn pending_rbc_snapshot_includes_entry_drop_counts() {
    super::status::reset_pending_rbc_for_tests();
    let now = Instant::now();
    let block_hash = HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xDA; 32]));
    let key: SessionKey = (block_hash, 7, 0);
    let chunk = crate::sumeragi::consensus::RbcChunk {
        block_hash,
        height: key.1,
        view: key.2,
        epoch: 0,
        idx: 0,
        bytes: vec![1, 2, 3, 4],
    };

    let mut pending_entry = PendingRbcMessages::new(now);
    let _ = pending_entry.push_chunk_capped(chunk, 0, 0, now);
    let mut pending = BTreeMap::new();
    pending.insert(key, pending_entry);

    Actor::update_rbc_backlog_snapshot(
        &BTreeMap::new(),
        &pending,
        (1, 4),
        Duration::from_secs(1),
        None,
    );

    let snapshot = super::status::pending_rbc_snapshot();
    assert_eq!(snapshot.entries.len(), 1);
    let entry = &snapshot.entries[0];
    assert_eq!(entry.dropped_chunks, 1);
    assert_eq!(entry.dropped_bytes, 4);
    assert_eq!(entry.ready, 0);
    assert_eq!(entry.deliver, 0);

    super::status::reset_pending_rbc_for_tests();
}

#[test]
fn pending_rbc_ttl_counts_from_first_seen() {
    let now = Instant::now();
    let created = now.checked_sub(Duration::from_millis(50)).unwrap_or(now);
    let mut pending = PendingRbcMessages::new(created);
    pending.touch(Instant::now());

    assert!(
        pending.expired(Duration::from_millis(10), Instant::now()),
        "TTL should be measured from the first pending frame"
    );
}
